22	const MAIN_ITEM_BASE: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE = 60;
33	
34	const PROCESSING_FEE = 5;
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	const CURSED_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const LOYALTY_THRESHOLD_YEARS = 2;
40	const LOYALTY_DISCOUNT_RATE = 0.2;
41	
42	const componentGroupBase = (count: number): number => {
43	  if (count === BLOCK_SIZE) return BLOCK_BASE;
44	  return count * COMPONENT_BASE;
45	};
46	
47	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
48	
49	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
50	
51	const sumMainItems = (items: Item[]): number =>
52	  mainItems(items).reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
53	
54	const countByType = (items: Item[]): Record<string, number> => {
55	  const counts: Record<string, number> = {};
56	  for (const item of items) {
57	    counts[item.type] = (counts[item.type] ?? 0) + 1;
58	  }
59	  return counts;
60	};
61	
62	const sumComponentGroups = (items: Item[]): number => {
63	  const counts = countByType(items.filter(isComponent));
64	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
65	};
66	
67	const policyBasePremium = (items: Item[]): number =>
68	  sumMainItems(items) + sumComponentGroups(items);
69	
70	const cursedSurcharge = (item: Item): number => {
71	  const base = MAIN_ITEM_BASE[item.type];
72	  return item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
73	};
74	
75	const highEnchantmentSurcharge = (item: Item): number => {
76	  const base = MAIN_ITEM_BASE[item.type];
77	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
78	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
79	    : 0;
80	};
81	
82	const itemSurcharges = (items: Item[]): number =>
83	  mainItems(items).reduce(
84	    (total, item) => total + cursedSurcharge(item) + highEnchantmentSurcharge(item),
85	    0,
86	  );
87	
88	const loyaltyDiscount = (base: number, customer: Customer): number =>
89	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
90	
91	const quotePremium = (step: QuoteStep, customer: Customer): number => {
92	  const base = policyBasePremium(step.items);
93	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
94	  const modified = withFirstInsurance - loyaltyDiscount(base, customer) + itemSurcharges(step.items);
95	  return Math.ceil(modified) + PROCESSING_FEE;
96	};
97	
98	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
99	  const results = scenario.steps.map((step) => ({
100	    premium: quotePremium(step, scenario.customer),
101	  }));
102	  return { results };
103	};
