const adjustedPremium = (items: Item[], customer: Customer): number => {
  const base = policyBasePremium(items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
  return base + firstInsuranceSurcharge - loyaltyDiscount(base, customer) + itemSurcharges(items);
};

const quotePremium = (step: QuoteStep, customer: Customer): number =>
  Math.ceil(adjustedPremium(step.items, customer)) + PROCESSING_FEE;
